#!/usr/bin/env node
/**
 * setup-biometric-platforms.js
 *
 * Patches the native platform files generated by `npx cap add ios` /
 * `npx cap add android` to include the permissions and usage strings
 * required by biometric authentication.
 *
 * Run ONCE after adding a new native platform:
 *   node scripts/setup-biometric-platforms.js
 *
 * It is idempotent – re-running it will not duplicate entries.
 */

import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, '..');

// ─── iOS – Info.plist ────────────────────────────────────────────────────────

const PLIST_PATH = resolve(ROOT, 'ios/App/App/Info.plist');

const FACE_ID_KEY   = '<key>NSFaceIDUsageDescription</key>';
const FACE_ID_VALUE = '<string>ShotSpot uses Face ID to let you sign in quickly and securely.</string>';

function patchInfoPlist() {
  if (!existsSync(PLIST_PATH)) {
    console.warn('[biometric] iOS Info.plist not found – run `npx cap add ios` first.');
    return;
  }

  let plist = readFileSync(PLIST_PATH, 'utf8');

  if (plist.includes(FACE_ID_KEY)) {
    console.log('[biometric] iOS: NSFaceIDUsageDescription already present.');
    return;
  }

  // Insert before the closing </dict> tag
  plist = plist.replace('</dict>\n</plist>', `\t${FACE_ID_KEY}\n\t${FACE_ID_VALUE}\n</dict>\n</plist>`);
  writeFileSync(PLIST_PATH, plist, 'utf8');
  console.log('[biometric] iOS: Added NSFaceIDUsageDescription to Info.plist.');
}

// ─── Android – AndroidManifest.xml ──────────────────────────────────────────

const MANIFEST_PATH = resolve(ROOT, 'android/app/src/main/AndroidManifest.xml');

const BIOMETRIC_PERMISSION    = '<uses-permission android:name="android.permission.USE_BIOMETRIC" />';
const FINGERPRINT_PERMISSION  = '<uses-permission android:name="android.permission.USE_FINGERPRINT" />';

function patchAndroidManifest() {
  if (!existsSync(MANIFEST_PATH)) {
    console.warn('[biometric] Android AndroidManifest.xml not found – run `npx cap add android` first.');
    return;
  }

  let manifest = readFileSync(MANIFEST_PATH, 'utf8');
  let changed = false;

  if (!manifest.includes(BIOMETRIC_PERMISSION)) {
    manifest = manifest.replace('<application', `${BIOMETRIC_PERMISSION}\n    <application`);
    changed = true;
  }

  if (!manifest.includes(FINGERPRINT_PERMISSION)) {
    manifest = manifest.replace('<application', `${FINGERPRINT_PERMISSION}\n    <application`);
    changed = true;
  }

  if (changed) {
    writeFileSync(MANIFEST_PATH, manifest, 'utf8');
    console.log('[biometric] Android: Added USE_BIOMETRIC and USE_FINGERPRINT permissions.');
  } else {
    console.log('[biometric] Android: Biometric permissions already present.');
  }
}

// ─── Run ─────────────────────────────────────────────────────────────────────

patchInfoPlist();
patchAndroidManifest();
console.log('[biometric] Platform setup complete.');
